let LANG = localStorage.getItem('4d-lang') || 'en';
function t(key) { return (I18N[LANG] && I18N[LANG][key]) || I18N.en[key] || key; }

function applyI18n() {
  document.documentElement.lang = LANG;
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    if (I18N[LANG][key]) el.textContent = I18N[LANG][key];
  });
  document.getElementById('search').placeholder = I18N[LANG].placeholder;
  document.querySelectorAll('.lang-btn').forEach(b => {
    b.classList.toggle('active', b.dataset.lang === LANG);
  });
  // re-render list title and rows in current language
  if (typeof searchInput !== 'undefined' && searchInput.value.trim() !== '') {
    if (typeof doSearch === 'function') doSearch();
  } else {
    if (typeof listTitleEl !== 'undefined') listTitleEl.innerHTML = `<span>${t('all_entries')}</span>`;
    if (typeof renderList === 'function') renderList();
  }
}

document.querySelectorAll('.lang-btn').forEach(btn => {
  btn.addEventListener('click', () => {
    LANG = btn.dataset.lang;
    localStorage.setItem('4d-lang', LANG);
    applyI18n();
  });
});

